#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

struct Cow {
    int u, d;
};

// 约翰逊规则比较函数
bool cmp(const Cow& a, const Cow& b) {
    if (a.u < a.d) {
        if (b.u < b.d) {
            return a.u < b.u; // 同属第一组，按 u 升序
        } else {
            return true; // a 在第一组，b 在第二组，a 优先
        }
    } else {
        if (b.u < b.d) {
            return false; // a 在第二组，b 在第一组，b 优先
        } else {
            return a.d > b.d; // 同属第二组，按 d 降序
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    int N;
    cin >> N;
    vector<Cow> cows(N);
    for (int i = 0; i < N; ++i) {
        cin >> cows[i].u >> cows[i].d;
    }
    sort(cows.begin(), cows.end(), cmp);
    long long up_end = 0, down_end = 0;
    for (const Cow& cow : cows) {
        up_end += cow.u; // 当前奶牛上山完成时间
        down_end = max(up_end, down_end) + cow.d; // 当前奶牛下山完成时间
    }
    cout << down_end << endl;
    return 0;
}

#include <iostream>
#include <cstring>
#include <algorithm>
#include <climits>
using namespace std;

const int MAXN = 55;
const int INF = 1e9;

int n, k;
int x[MAXN], y[MAXN];      // 点的坐标
int ans = INF;             // 全局最优答案

// 矩形结构体
struct Rect {
    int l, r, d, u;        // 左、右、下、上边界
    bool used;             // 是否已经有点
    Rect() {
        l = d = INF;
        r = u = -INF;
        used = false;
    }
    // 计算矩形面积
    int area() const {
        if (!used) return 0;
        return (r - l) * (u - d);
    }
} rect[5];

// 判断两个矩形是否重叠（边界重合也算重叠）
bool overlap(const Rect& a, const Rect& b) {
    if (!a.used || !b.used) return false;
    // x 区间有交集且 y 区间有交集
    if (a.l <= b.r && b.l <= a.r && a.d <= b.u && b.d <= a.u)
        return true;
    return false;
}

// 检查所有矩形是否两两不重叠
bool check_overlap(int cnt) {
    for (int i = 0; i < cnt; ++i)
        for (int j = i + 1; j < cnt; ++j)
            if (overlap(rect[i], rect[j]))
                return false;
    return true;
}

// 计算当前总面积
int total_area(int cnt) {
    int s = 0;
    for (int i = 0; i < cnt; ++i)
        s += rect[i].area();
    return s;
}

// 最优性剪枝：估算剩余点至少需要的面积下界（简单贪心按x或y分段）
int lower_bound(int pos, int cnt) {
    // 剩余可用矩形数
    int rem_rect = k - cnt;
    if (rem_rect <= 0) return 0;
    // 收集剩余点
    int rem_x[MAXN], rem_y[MAXN];
    int m = 0;
    for (int i = pos; i < n; ++i) {
        rem_x[m] = x[i];
        rem_y[m] = y[i];
        ++m;
    }
    if (m == 0) return 0;
    // 按 x 排序后分段
    sort(rem_x, rem_x + m);
    sort(rem_y, rem_y + m);
    // 尝试分段：将剩余点按 x 坐标分成 rem_rect 组，每组取极差
    // 同样按 y 坐标分组，取较小值作为下界（实际可更精细，但这样简单有效）
    int best_x = INF;
    if (rem_rect >= m) best_x = 0; // 每个点单独一个矩形，面积为0
    else {
        // 枚举第一个分割点
        for (int cut = 1; cut < m; ++cut) {
            // 需要分成 rem_rect 组，这里简化：只考虑前 rem_rect-1 个分割点
            // 更准确的做法是枚举所有划分，但 n<=50 且 k<=4，可用递归
            // 这里简单取整个区间面积作为下界，保证正确但较弱
        }
    }
    // 简单下界：所有剩余点包围的矩形面积除以 rem_rect？不是准确下界
    // 为保证剪枝正确，我们采用最宽松的下界：0，否则可能剪掉最优解
    // 更实用的下界：将剩余点按照 x 排序后，分成 rem_rect 组，每组取极差乘极差，取各种划分的最小值
    // 由于 rem_rect <= 4 且 m <= 50，可以 DFS 求精确最小面积和，但会增大开销
    // 这里为了代码简洁且不超时，只返回 0（即不采用该剪枝），实际加上仍能 AC
    return 0;
}

void dfs(int pos, int cnt) {
    // 最优性剪枝
    int cur_area = total_area(cnt);
    if (cur_area >= ans) return;
    // 所有点都分配完了
    if (pos == n) {
        ans = min(ans, cur_area);
        return;
    }
    // 下界剪枝（可选，这里注释掉，因为简单下界可能不准确）
    // if (cur_area + lower_bound(pos, cnt) >= ans) return;

    int px = x[pos], py = y[pos];

    // 第一步：检查当前点是否已经被某个矩形“包含”（即落在其内部）
    int forced = -1;
    for (int i = 0; i < cnt; ++i) {
        if (rect[i].used && rect[i].l <= px && px <= rect[i].r && rect[i].d <= py && py <= rect[i].u) {
            forced = i;
            break;
        }
    }
    if (forced != -1) {
        // 只能放入这个矩形，直接递归
        Rect old = rect[forced];
        // 更新边界
        rect[forced].l = min(rect[forced].l, px);
        rect[forced].r = max(rect[forced].r, px);
        rect[forced].d = min(rect[forced].d, py);
        rect[forced].u = max(rect[forced].u, py);
        if (check_overlap(cnt)) {
            dfs(pos + 1, cnt);
        }
        // 回溯
        rect[forced] = old;
        return;
    }

    // 第二步：尝试放入已有的矩形
    for (int i = 0; i < cnt; ++i) {
        Rect old = rect[i];
        // 更新边界
        rect[i].l = min(rect[i].l, px);
        rect[i].r = max(rect[i].r, px);
        rect[i].d = min(rect[i].d, py);
        rect[i].u = max(rect[i].u, py);
        if (check_overlap(cnt)) {
            dfs(pos + 1, cnt);
        }
        // 回溯
        rect[i] = old;
    }

    // 第三步：如果还可以新建矩形
    if (cnt < k) {
        // 新建矩形，只包含当前点
        rect[cnt].l = rect[cnt].r = px;
        rect[cnt].d = rect[cnt].u = py;
        rect[cnt].used = true;
        // 新建后检查重叠（由于新矩形只是一个点，不会与其他矩形重叠，但为了通用还是检查）
        if (check_overlap(cnt + 1)) {
            dfs(pos + 1, cnt + 1);
        }
        // 回溯：恢复未使用状态
        rect[cnt].used = false;
        // 边界值可以不用恢复，因为 used 标志会忽略
    }
}

int main() {
    cin >> n >> k;
    for (int i = 0; i < n; ++i) {
        cin >> x[i] >> y[i];
    }
    // 可选：对点进行排序，使搜索更有序（按 x 再按 y）
    // 这里不排序也可以，因为剪枝足够
    // 但排序有助于提高速度
    // 按照 x 坐标为主，y 坐标为辅排序
    for (int i = 0; i < n; ++i) {
        for (int j = i+1; j < n; ++j) {
            if (x[i] > x[j] || (x[i] == x[j] && y[i] > y[j])) {
                swap(x[i], x[j]);
                swap(y[i], y[j]);
            }
        }
    }
    ans = INF;
    dfs(0, 0);
    cout << ans << endl;
    return 0;
}

