int binary_search(int arr[], int l, int r, int x) {
	while (l <= r) {
		int m = l + (r - l) / 2;
		if (arr[m] == x) {
			return 1;
		}
		if (arr[m] < x) {
			l = m + 1;
		} else {
			r = m - 1;
		}
	}
	return 0;
}

