    cin >> m;        // 目标进制

    // 1. 将n进制数转换为十进制
    long long decimal = 0;
    int len = num.length();

    for(int i = 0; i < len; i++) {
        int digit;

        if(num[i] >= '0' && num[i] <= '9') {
            digit = num[i] - '0';
        } else {
            digit = num[i] - 'A' + 10;
        }

        decimal = decimal * n + digit;
    }


    if(decimal == 0) {
        cout << "0" << endl;
        return 0;
    }

    string result = "";
    while(decimal > 0) {
        int remainder = decimal % m;
        if(remainder < 10) {
            result += char(remainder + '0');
        } else {
            result += char(remainder - 10 + 'A');
        }
        decimal /= m;
    }

    reverse(result.begin(), result.end());

    cout << result << endl;

    return 0;
}

