#include <iostream>
#include <cmath>
using namespace std;

// 计算 x 的二进制逆序，位数为 k（k <= 17）
int reverseBits(int x, int k) {
    int res = 0;
    for (int i = 0; i < k; ++i) {
        res = (res << 1) | (x & 1);
        x >>= 1;
    }
    return res;
}

int main() {
    int n;
    cin >> n;

    int maxLen = 0;
    while ((1 << maxLen) <= n) ++maxLen;  // 最大二进制位数

    int cnt = 0;
    // 枚举所有可能的二进制长度
    for (int len = 1; len <= maxLen; ++len) {
        if (len % 2 == 0) {   // 偶数长度
            int halfLen = len / 2;
            int start = 1 << (halfLen - 1);   // 前半部分最小值，保证最高位为1
            int end = (1 << halfLen) - 1;
            for (int half = start; half <= end; ++half) {
                int rev = reverseBits(half, halfLen);
                int pal = (half << halfLen) | rev;
                if (pal <= n) ++cnt;
                // 由于前半部分递增，pal也递增，但n比较小，直接判断即可
            }
        } else {               // 奇数长度
            int halfLen = (len + 1) / 2;   // 包括中间位的前半部分长度
            int start = 1 << (halfLen - 1);
            int end = (1 << halfLen) - 1;
            for (int half = start; half <= end; ++half) {
                // 取高位部分（去掉最低位）进行逆序，最低位作为中间位
                int high = half >> 1;
                int rev = reverseBits(high, halfLen - 1);
                int pal = (half << (halfLen - 1)) | rev;
                if (pal <= n) ++cnt;
            }
        }
    }

    cout << cnt << endl;
    return 0;
}

