// 判断字符串 s 从索引 l 到 r（包含）的子串是否是回文串
bool isPalindrome(const string &s, int l, int r) {
    while (l < r) {
        if (s[l] != s[r]) {
            return false;
        }
        l++;
        r--;
    }
    return true;
}

