long long gcd(long long a, long long b) {
    while (b != 0) {
        long long t = b;
        b = a % b;
        a = t;
    }
    return a;
}

long long lcm(long long a, long long b) {
    return a / gcd(a, b) * b;
}

long long lcm_of_n_numbers(vector<long long>& nums) {
    if (nums.empty()) return 0;
    long long result = 1;
    for (long long x : nums) {
        result = lcm(result, x);
        if (result == 0) return 0;
    }
    return result;
}

