#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>
using namespace std;

const string days[7] = {"Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"};

int M, N, P;
vector<string> names;
map<string, int> name2id;

struct Statement {
    int type;  // 1: I am guilty. 2: I am not guilty. 3: XX is guilty. 4: XX is not guilty. 5: Today is XXX.
    int param;
};

vector<vector<Statement>> statements;

Statement parse(const string& s) {
    Statement st;
    st.type = 0;

    if (s == "I am guilty.") {
        st.type = 1;
    } else if (s == "I am not guilty.") {
        st.type = 2;
    } else if (s.size() >= 11 && s.substr(s.size() - 11) == " is guilty.") {
        string name = s.substr(0, s.size() - 11);
        if (name2id.count(name)) {
            st.type = 3;
            st.param = name2id[name];
        }
    } else if (s.size() >= 15 && s.substr(s.size() - 15) == " is not guilty.") {
        string name = s.substr(0, s.size() - 15);
        if (name2id.count(name)) {
            st.type = 4;
            st.param = name2id[name];
        }
    } else if (s.size() >= 9 && s.substr(0, 9) == "Today is " && s.back() == '.') {
        string day = s.substr(9, s.size() - 10);
        for (int i = 0; i < 7; i++) {
            if (day == days[i]) {
                st.type = 5;
                st.param = i;
                break;
            }
        }
    }
    return st;
}

int main() {
    cin >> M >> N >> P;
    names.resize(M + 1);
    statements.resize(M + 1);

    for (int i = 1; i <= M; i++) {
        cin >> names[i];
        name2id[names[i]] = i;
    }

    cin.ignore();

    for (int i = 0; i < P; i++) {
        string line;
        getline(cin, line);
        if (line.empty()) continue;
        size_t pos = line.find(':');
        if (pos == string::npos) continue;
        string speaker = line.substr(0, pos);
        if (!name2id.count(speaker)) continue;
        int id = name2id[speaker];
        string content = line.substr(pos + 2);
        Statement st = parse(content);
        if (st.type != 0) {
            statements[id].push_back(st);
        }
    }

    vector<int> possible;

    for (int criminal = 1; criminal <= M; criminal++) {
        for (int day = 0; day < 7; day++) {
            vector<int> state(M + 1, 0);
            bool valid = true;

            for (int person = 1; person <= M; person++) {
                for (auto& st : statements[person]) {
                    bool truth;
                    switch (st.type) {
                        case 1:
                            truth = (person == criminal);
                            break;
                        case 2:
                            truth = (person != criminal);
                            break;
                        case 3:
                            truth = (st.param == criminal);
                            break;
                        case 4:
                            truth = (st.param != criminal);
                            break;
                        case 5:
                            truth = (st.param == day);
                            break;
                        default:
                            continue;
                    }
                    if (state[person] == 0) {
                        state[person] = truth ? 1 : -1;
                    } else if ((state[person] == 1 && !truth) || (state[person] == -1 && truth)) {
                        valid = false;
                        break;
                    }
                }
                if (!valid) break;
            }
            if (!valid) continue;

            int liar = 0, unknown = 0;
            for (int i = 1; i <= M; i++) {
                if (state[i] == -1) liar++;
                else if (state[i] == 0) unknown++;
            }
            if (liar <= N && liar + unknown >= N) {
                possible.push_back(criminal);
                break;
            }
        }
    }

    sort(possible.begin(), possible.end());
    possible.erase(unique(possible.begin(), possible.end()), possible.end());

    if (possible.empty()) {
        cout << "Impossible" << endl;
    } else if (possible.size() == 1) {
        cout << names[possible[0]] << endl;
    } else {
        cout << "Cannot Determine" << endl;
    }

    return 0;
}

